#!/usr/bin/env bash
# Smoke test for the in-room protocol69 SDR app-teleport bench.
#
#   Default (--preflight): toolchain check + device enumeration + marker table.
#                          No RF is radiated. Safe to run anytime.
#   --teleport:            full over-the-air loopback. Encodes a payload, keys the
#                          Pluto, RADIATES on 433.92 MHz ISM, captures on an RTL,
#                          decodes, and asserts the payload round-tripped bit-exact.
#
# Reference bench (override serials/URIs via env if your kit differs):
#   RX  2x Nooelec NESDR SMArt v5  -- Realtek RTL2832U + R820T, RX-only
#          USB  0x0BDA:0x2838 (vendor "Nooelec")   serials 78922015, 94092559
#   TX  1x ADALM-Pluto Rev.C       -- Analog Devices Z7010-AD9361, TX+RX
#          USB  0x0456:0xB673  product "PlutoSDR (ADALM-PLUTO)"
#          libiio URI usb:X.Y.Z (VARIES per enumeration -> auto-discovered)
#
# protocol69 admission: broadcastSymbol 66 XOR localFoilOperand 7 = 69.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
GNOSIS_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"

# ---- expected device markers (override via env) ----------------------------
RTL_USB_VID="${RTL_USB_VID:-0bda}"            # Realtek
RTL_USB_PID="${RTL_USB_PID:-2838}"            # RTL2832U
RTL_PRODUCT="${RTL_PRODUCT:-NESDR SMArt v5}"
EXPECTED_RTL_COUNT="${EXPECTED_RTL_COUNT:-2}"
EXPECTED_RTL_SERIALS="${EXPECTED_RTL_SERIALS:-78922015 94092559}"
PLUTO_USB_VID="${PLUTO_USB_VID:-0456}"        # Analog Devices
PLUTO_USB_PID="${PLUTO_USB_PID:-b673}"
PLUTO_VENDOR_HINT="${PLUTO_VENDOR_HINT:-Analog Devices}"

# ---- toolchain locations ----------------------------------------------------
LIBIIO_BUILD="${GNOSIS_LIBIIO_BUILD:-/tmp/libiio_build/build}"
export DYLD_FALLBACK_FRAMEWORK_PATH="${LIBIIO_BUILD}${DYLD_FALLBACK_FRAMEWORK_PATH:+:${DYLD_FALLBACK_FRAMEWORK_PATH}}"
IIO_INFO="${LIBIIO_BUILD}/tests/iio_info"
IIO_ATTR="${LIBIIO_BUILD}/tests/iio_attr"
IIO_WRITEDEV="${LIBIIO_BUILD}/tests/iio_writedev"
CLI=("node" "${GNOSIS_ROOT}/bin/rtlsdr-mock-sim.js")

# ---- RF parameters ----------------------------------------------------------
TX_LO_HZ="${TX_LO_HZ:-433920000}"             # 433.92 MHz ISM
SAMPLE_RATE="${SAMPLE_RATE:-2400000}"
TX_GAIN_DB="${TX_GAIN_DB:--10}"               # hardwaregain (attenuation toward 0 = hotter)
RX_DEVICE="${RX_DEVICE:-0}"
RX_TUNER_GAIN="${RX_TUNER_GAIN:-30}"
CAPTURE_SECONDS="${CAPTURE_SECONDS:-3}"
ARTIFACT_DIR="${GNOSIS_ROOT}/.qa-artifacts/rtlsdr"
PAYLOAD="${PAYLOAD:-GNOSIS-SMOKE/1 teleported across the room p69=66xor7=69}"

RED=$'\033[0;31m'; GREEN=$'\033[0;32m'; YELLOW=$'\033[1;33m'; BLUE=$'\033[0;34m'; NC=$'\033[0m'
info(){ echo "${BLUE}[smoke]${NC} $*"; }
ok(){   echo "${GREEN}[ ok ]${NC} $*"; }
warn(){ echo "${YELLOW}[warn]${NC} $*" >&2; }
err(){  echo "${RED}[FAIL]${NC} $*" >&2; }

MODE="preflight"
case "${1:-}" in
  --teleport) MODE="teleport" ;;
  --preflight|"") MODE="preflight" ;;
  -h|--help)
    sed -n '2,20p' "${BASH_SOURCE[0]}" | sed 's/^# \{0,1\}//'
    exit 0 ;;
  *) err "unknown argument: $1"; exit 2 ;;
esac

FAILURES=0
need_bin(){ command -v "$1" >/dev/null 2>&1 || [[ -x "/opt/homebrew/bin/$1" || -x "/usr/local/bin/$1" ]]; }
rtl_bin(){ command -v "$1" 2>/dev/null || { [[ -x "/opt/homebrew/bin/$1" ]] && echo "/opt/homebrew/bin/$1"; } || echo "$1"; }

# ---------------------------------------------------------------------------
# 1. Toolchain
# ---------------------------------------------------------------------------
info "checking toolchain"
for b in rtl_test rtl_sdr; do
  if need_bin "$b"; then ok "$b: $(rtl_bin "$b")"; else err "$b missing (brew install rtl-sdr)"; FAILURES=$((FAILURES+1)); fi
done
for t in "$IIO_INFO" "$IIO_ATTR" "$IIO_WRITEDEV"; do
  if [[ -x "$t" ]]; then ok "$(basename "$t"): $t"; else err "$(basename "$t") missing (run scripts/setup-sdr-toolchain.sh --build)"; FAILURES=$((FAILURES+1)); fi
done

# ---------------------------------------------------------------------------
# 2. RX enumeration (RTL-SDR)
# ---------------------------------------------------------------------------
info "enumerating RTL-SDR receivers"
RTL_OUT="$(timeout 8 "$(rtl_bin rtl_test)" -t 2>&1 || true)"
RTL_COUNT="$(printf '%s\n' "$RTL_OUT" | grep -oE 'Found [0-9]+ device' | grep -oE '[0-9]+' || echo 0)"
RTL_COUNT="${RTL_COUNT:-0}"
FOUND_SERIALS="$(printf '%s\n' "$RTL_OUT" | grep -oE 'SN: [0-9]+' | awk '{print $2}' | tr '\n' ' ')"
echo "      device count: ${RTL_COUNT} (expected ${EXPECTED_RTL_COUNT})"
echo "      serials found: ${FOUND_SERIALS:-<none>}"
echo "      serials expect: ${EXPECTED_RTL_SERIALS}"
if [[ "$RTL_COUNT" -ge "$EXPECTED_RTL_COUNT" ]]; then ok "RTL count OK"; else warn "RTL count ${RTL_COUNT} < expected ${EXPECTED_RTL_COUNT} (charge-only cable / unpowered hub?)"; fi
[[ "$RTL_COUNT" -ge 1 ]] || { err "no RTL receivers — cannot decode"; FAILURES=$((FAILURES+1)); }

# ---------------------------------------------------------------------------
# 3. TX enumeration (Pluto) + URI auto-discovery
# ---------------------------------------------------------------------------
info "discovering ADALM-Pluto (libiio)"
PLUTO_URI=""
if [[ -x "$IIO_INFO" ]]; then
  SCAN="$("$IIO_INFO" -s 2>&1 || true)"
  PLUTO_URI="$(printf '%s\n' "$SCAN" | grep -iE 'pluto|adalm|analog devices|0456:b673' | grep -oE 'usb:[0-9]+\.[0-9]+\.[0-9]+' | head -1 || true)"
  if [[ -z "$PLUTO_URI" ]]; then
    PLUTO_URI="$(printf '%s\n' "$SCAN" | grep -oE 'usb:[0-9]+\.[0-9]+\.[0-9]+' | sort -u | head -1 || true)"
  fi
fi
PLUTO_URI="${GNOSIS_PLUTO_URI:-$PLUTO_URI}"

if [[ -n "$PLUTO_URI" ]]; then
  HWMODEL="$("$IIO_INFO" -u "$PLUTO_URI" 2>/dev/null | grep -m1 'hw_model:' | sed 's/.*hw_model: //' || true)"
  ok "Pluto URI: ${PLUTO_URI}"
  echo "      hw_model: ${HWMODEL:-<unreadable>}"
  echo "      mass-storage volume: $(ls /Volumes 2>/dev/null | grep -i pluto || echo '(none — normal on macOS)')"
  echo "      serial port: $(ls /dev/cu.usbmodem* 2>/dev/null | head -1 || echo '(none)')"
else
  warn "no Pluto on the bus (Analog Devices ${PLUTO_USB_VID}:${PLUTO_USB_PID} absent). TX leg unavailable."
  warn "  -> check: DATA cable (not charge-only) in the Pluto DATA jack; LED1 solid; powered hub."
fi

# ---------------------------------------------------------------------------
# 4. Marker table
# ---------------------------------------------------------------------------
info "device markers"
cat <<EOF
  ----------------------------------------------------------------------------
  RX  RTL-SDR    USB ${RTL_USB_VID}:${RTL_USB_PID}  "${RTL_PRODUCT}"  count=${RTL_COUNT}
  TX  Pluto      USB ${PLUTO_USB_VID}:${PLUTO_USB_PID}  "${PLUTO_VENDOR_HINT}"  uri=${PLUTO_URI:-<absent>}
  RF  carrier=${TX_LO_HZ} Hz  rate=${SAMPLE_RATE} S/s  tx_gain=${TX_GAIN_DB} dB
  p69 66 XOR 7 = 69
  ----------------------------------------------------------------------------
EOF

if [[ "$MODE" == "preflight" ]]; then
  if [[ "$FAILURES" -eq 0 ]]; then ok "PREFLIGHT PASS — bench ready${PLUTO_URI:+ (run with --teleport for the OTA loopback)}"; exit 0
  else err "PREFLIGHT FAIL — ${FAILURES} blocker(s) above"; exit 1; fi
fi

# ---------------------------------------------------------------------------
# 5. --teleport: full over-the-air loopback (RADIATES RF)
# ---------------------------------------------------------------------------
[[ "$FAILURES" -eq 0 ]]   || { err "toolchain/RX blockers above; refusing to teleport"; exit 1; }
[[ -n "$PLUTO_URI" ]]     || { err "no Pluto transmitter; cannot teleport"; exit 1; }
mkdir -p "$ARTIFACT_DIR"
IQ="${ARTIFACT_DIR}/smoke-teleport.iq16"
CAP="${ARTIFACT_DIR}/smoke-capture.u8"

info "encoding payload -> IQ (mars-tx)"
echo "      payload: ${PAYLOAD}"
TX_JSON="$(GNOSIS_PLUTO_URI="$PLUTO_URI" "${CLI[@]}" mars-tx --payload "$PAYLOAD" --tx-lo-hz "$TX_LO_HZ" --iq-int16-out "$IQ" 2>&1)"
FRAME_SAMPLES="$(printf '%s' "$TX_JSON" | node -e 'let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{try{console.log(JSON.parse(s).frameSamples)}catch{process.exit(1)}})')"
[[ -n "$FRAME_SAMPLES" ]] || { err "mars-tx failed:"; printf '%s\n' "$TX_JSON" | tail -5; exit 1; }
ok "frame=${FRAME_SAMPLES} samples, IQ=$(ls -la "$IQ" | awk '{print $5}') bytes"

info "configuring Pluto TX chain @ ${PLUTO_URI}"
"$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy altvoltage1 frequency "$TX_LO_HZ"       >/dev/null 2>&1 || true
"$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy voltage0 sampling_frequency "$SAMPLE_RATE" >/dev/null 2>&1 || true
"$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy voltage0 rf_bandwidth "$SAMPLE_RATE"     >/dev/null 2>&1 || true
# hardwaregain writes can throw EMULTIHOP(95) over USB yet still take — retry + readback.
for _ in 1 2 3; do "$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy voltage0 hardwaregain "$TX_GAIN_DB" >/dev/null 2>&1 || true; done
GAIN_RB="$("$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy voltage0 hardwaregain 2>/dev/null | tail -1 || echo '?')"
LO_RB="$("$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy altvoltage1 frequency 2>/dev/null | tail -1 || echo '?')"
ok "readback: LO=${LO_RB} gain=${GAIN_RB}"

info "cyclic TX (background) + ${CAPTURE_SECONDS}s capture on RTL#${RX_DEVICE}"
"$IIO_WRITEDEV" -u "$PLUTO_URI" -b "$FRAME_SAMPLES" -c cf-ad9361-dds-core-lpc voltage0 voltage1 < "$IQ" >/tmp/smoke-pluto-tx.log 2>&1 &
TXPID=$!
RX_SAMPLES=$(( SAMPLE_RATE * CAPTURE_SECONDS ))
timeout $(( CAPTURE_SECONDS + 10 )) "$(rtl_bin rtl_sdr)" -d "$RX_DEVICE" -f "$TX_LO_HZ" -s "$SAMPLE_RATE" -g "$RX_TUNER_GAIN" -n "$RX_SAMPLES" "$CAP" >/dev/null 2>&1 || true
kill "$TXPID" 2>/dev/null || true; wait "$TXPID" 2>/dev/null || true
CAP_BYTES="$(ls -la "$CAP" 2>/dev/null | awk '{print $5}' || echo 0)"
ok "captured ${CAP_BYTES} bytes"

info "decoding (mars-rx) + verifying round-trip"
RX_JSON="$("${CLI[@]}" mars-rx --iq-file "$CAP" --payload "$PAYLOAD" --capture-format rtl_u8 2>&1)"
VERDICT="$(printf '%s' "$RX_JSON" | node -e 'let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{try{const j=JSON.parse(s);const a=(j.attempts&&j.attempts[0])||{};console.log([j.ok,j.matchesExpected,a.syncScore,a.rsErrors,JSON.stringify(j.recoveredAscii||"")].join("|"))}catch{console.log("parse-fail")}})')"
IFS='|' read -r R_OK R_MATCH R_SYNC R_RS R_RECOVERED <<<"$VERDICT"

echo "      ok=${R_OK} matches=${R_MATCH} sync=${R_SYNC} rsErrors=${R_RS}"
echo "      recovered: ${R_RECOVERED}"
if [[ "$R_OK" == "true" && "$R_MATCH" == "true" ]]; then
  ok "TELEPORT PASS — payload round-tripped over the air, bit-exact"
  exit 0
else
  err "TELEPORT FAIL — decode mismatch (antenna/gain/proximity?). raw mars-rx:"; printf '%s\n' "$RX_JSON" | tail -8
  exit 1
fi
